keyframes.cssText:
@keyframes _slideDown_1kq03_1 { 
  0% { max-block-size: 0px; opacity: 0; }
  50% { opacity: 0; }
  100% { max-block-size: var(--radix-accordion-content-height); opacity: 1; }
}

@keyframes _slideUp_1kq03_1 { 
  0% { max-block-size: var(--radix-accordion-content-height); opacity: 1; }
  20% { opacity: 0; }
  100% { max-block-size: 0px; opacity: 0; }
}

@keyframes _rotatingGradientBorder_10iw9_1 { 
  0% { transform: translate(-50%, -50%) rotate(0deg); }
  100% { transform: translate(-50%, -50%) rotate(1turn); }
}

@keyframes _mediaFadeUpOut_36zu8_1 { 
  0% { transform: translateY(0px); opacity: 1; }
  100% { transform: translateY(-30px); opacity: 0; }
}

@keyframes _mediaFadeUpIn_36zu8_1 { 
  0% { transform: translateY(10px); opacity: 0; }
  100% { transform: translateY(0px); opacity: 1; }
}

@keyframes _pillExpandFromCorner_36zu8_1 { 
  0% { transform: scale(0.92); opacity: 0.65; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes _borderPulse_12c7p_1 { 
  0% { box-shadow: rgba(0, 145, 255, 0.3) 0px 0px; }
  50% { box-shadow: rgba(0, 145, 255, 0.1) 0px 0px 0px 4px; }
  100% { box-shadow: rgba(0, 145, 255, 0) 0px 0px; }
}

@keyframes _logoEnter_10zz2_1 { 
  0% { opacity: 0; filter: blur(5px); transform: scale(0.8) translateZ(0px); }
  100% { opacity: 1; filter: blur(0px); transform: scale(1) translateZ(0px); }
}

@keyframes _logoExit_10zz2_1 { 
  0% { opacity: 1; filter: blur(0px); transform: scale(1) translateZ(0px); }
  100% { opacity: 0; filter: blur(5px); transform: scale(0.8) translateZ(0px); }
}

@keyframes _curtainDown_l0952_66 { 
  0% { block-size: 0px; padding-block-end: 0px; opacity: 0; }
  100% { block-size: var(--current-height); padding-block-end: var(--padding-block-end); opacity: 1; }
}

@keyframes _curtainUp_l0952_70 { 
  0% { block-size: var(--previous-height); padding-block-end: var(--padding-block-end); opacity: 1; }
  30% { block-size: var(--previous-height); padding-block-end: var(--padding-block-end); opacity: 1; }
  100% { block-size: 0px; padding-block-end: 0px; opacity: 0; }
}

@keyframes _curtainContractUp_l0952_78 { 
  0% { block-size: var(--previous-height); }
  30% { block-size: var(--previous-height); }
  100% { block-size: var(--current-height); }
}

@keyframes _columnContentReveal_l0952_1 { 
  0% { opacity: 0; transform: translateY(-10px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes _columnContentFadeOut_l0952_1 { 
  0% { opacity: 1; transform: translateY(0px); }
  100% { opacity: 0; transform: translateY(-5px); }
}
